u16 FollowerMon_GetGfxID(u16 species, u8 form, BOOL isFemale, BOOL isShiny)
{
    const FollowerMonGfxEntry *entry;
    if (species == SPECIES_NONE || species > SPECIES_ARCEUS) {
        return OBJ_EVENT_GFX_INVISIBLE;
    }
    entry = &sFollowerMonGfxTable[species];
    if (entry->male == 0) {
        return OBJ_EVENT_GFX_INVISIBLE;
    }
    switch (species) {
    case SPECIES_GIRATINA:
        if (form == GIRATINA_FORM_ORIGIN) {
            return isShiny ? OBJ_EVENT_GFX_PKMN_GIRATINA_O_SHINY : OBJ_EVENT_GFX_PKMN_GIRATINA_O;
        }
        break;
    case SPECIES_ARCEUS:
        if (form < ARCEUS_FORM_COUNT) {
            return isShiny ? sArceusFormShinyGfx[form] : sArceusFormGfx[form];
        }
        break;
    case SPECIES_DEOXYS:
        switch (form) {
        case DEOXYS_FORM_ATTACK:  return isShiny ? OBJ_EVENT_GFX_PKMN_DEOXYS_ATTACK_SHINY  : OBJ_EVENT_GFX_PKMN_DEOXYS_ATTACK;
        case DEOXYS_FORM_DEFENSE: return isShiny ? OBJ_EVENT_GFX_PKMN_DEOXYS_DEFENSE_SHINY : OBJ_EVENT_GFX_PKMN_DEOXYS_DEFENSE;
        case DEOXYS_FORM_SPEED:   return isShiny ? OBJ_EVENT_GFX_PKMN_DEOXYS_SPEED_SHINY   : OBJ_EVENT_GFX_PKMN_DEOXYS_SPEED;
        }
        break;
    case SPECIES_BURMY:
        switch (form) {
        case BURMY_FORM_SAND:  return isShiny ? OBJ_EVENT_GFX_PKMN_BURMY_SANDY_SHINY : OBJ_EVENT_GFX_PKMN_BURMY_SANDY;
        case BURMY_FORM_TRASH: return isShiny ? OBJ_EVENT_GFX_PKMN_BURMY_TRASH_SHINY : OBJ_EVENT_GFX_PKMN_BURMY_TRASH;
        }
        break;
    case SPECIES_WORMADAM:
        switch (form) {
        case WORMADAM_FORM_SAND:  return isShiny ? OBJ_EVENT_GFX_PKMN_WORMADAM_SANDY_SHINY : OBJ_EVENT_GFX_PKMN_WORMADAM_SANDY;
        case WORMADAM_FORM_TRASH: return isShiny ? OBJ_EVENT_GFX_PKMN_WORMADAM_TRASH_SHINY : OBJ_EVENT_GFX_PKMN_WORMADAM_TRASH;
        }
        break;
    case SPECIES_SHELLOS:
        if (form == SHELLOS_FORM_EAST) {
            return isShiny ? OBJ_EVENT_GFX_PKMN_SHELLOS_EAST_SHINY : OBJ_EVENT_GFX_PKMN_SHELLOS_EAST;
        }
        break;
    case SPECIES_GASTRODON:
        if (form == GASTRODON_FORM_EAST) {
            return isShiny ? OBJ_EVENT_GFX_PKMN_GASTRODON_EAST_SHINY : OBJ_EVENT_GFX_PKMN_GASTRODON_EAST;
        }
        break;
    case SPECIES_ROTOM:
        switch (form) {
        case ROTOM_FORM_HEAT:  return isShiny ? OBJ_EVENT_GFX_PKMN_ROTOM_HEAT_SHINY  : OBJ_EVENT_GFX_PKMN_ROTOM_HEAT;
        case ROTOM_FORM_WASH:  return isShiny ? OBJ_EVENT_GFX_PKMN_ROTOM_WASH_SHINY  : OBJ_EVENT_GFX_PKMN_ROTOM_WASH;
        case ROTOM_FORM_FROST: return isShiny ? OBJ_EVENT_GFX_PKMN_ROTOM_FROST_SHINY : OBJ_EVENT_GFX_PKMN_ROTOM_FROST;
        case ROTOM_FORM_FAN:   return isShiny ? OBJ_EVENT_GFX_PKMN_ROTOM_FAN_SHINY   : OBJ_EVENT_GFX_PKMN_ROTOM_FAN;
        case ROTOM_FORM_MOW:   return isShiny ? OBJ_EVENT_GFX_PKMN_ROTOM_MOW_SHINY   : OBJ_EVENT_GFX_PKMN_ROTOM_MOW;
        }
        break;
    case SPECIES_SHAYMIN:
        if (form == SHAYMIN_FORM_SKY) {
            return isShiny ? OBJ_EVENT_GFX_PKMN_SHAYMIN_SKY_SHINY : OBJ_EVENT_GFX_PKMN_SHAYMIN_SKY;
        }
        break;
    }
    return isShiny ? (isFemale ? entry->female_shiny : entry->male_shiny) : (isFemale ? entry->female : entry->male);
}
